  1	import * as React from 'react';
  2	import { useDeepCompareMemoize } from '@odf/shared/hooks/deep-compare-memoize';
  3	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  4	import { getValidatedProp } from '@odf/shared/utils';
  5	import * as _ from 'lodash-es';
  6	import { TFunction } from 'react-i18next';
  7	import {
  8	  FormGroup,
  9	  TextInput,
 10	  FormHelperText,
 11	  HelperText,
 12	  HelperTextItem,
 13	  ValidatedOptions,
 14	} from '@patternfly/react-core';
 15	import { ThalesConfig, ProviderNames } from '../../types';
 16	import { FileUploadInput, UploadInputItem } from './file-upload-input';
 17	import { NameAddrPort } from './name-address-port';
 18	import { KMSConfigureProps } from './providers';
 19	import { kmsConfigValidation } from './utils';
 20	import './kms-config.scss';
 21	
 22	export const uploadInputItems: UploadInputItemType = (t) => [
 23	  {
 24	    id: 'clientCert',
 25	    inputName: t('Client certificate'),
 26	  },
 27	  {
 28	    id: 'caCert',
 29	    inputName: t('CA certificate'),
 30	  },
 31	  {
 32	    id: 'clientKey',
 33	    inputName: t('Client private key'),
 34	  },
 35	];
 36	
 37	export const ThalesConfigure: React.FC<KMSConfigureProps> = ({
 38	  state,
 39	  dispatch,
 40	  className,
 41	}) => {
 42	  const { t } = useCustomTranslation();
 43	
 44	  const thalesState = useDeepCompareMemoize(
 45	    state.kms.providerState,
 46	    true
 47	  ) as ThalesConfig;
 48	  const thalesStateClone: ThalesConfig = React.useMemo(
 49	    () => _.cloneDeep(thalesState),
 50	    [thalesState]
 51	  );
 52	
 53	  const { encryption } = state;
 54	  const isScEncryption = encryption.storageClass;
 55	
 56	  const updateThalesState = React.useCallback(
 57	    (kmsConfig: ThalesConfig) =>
 58	      dispatch({
 59	        type: 'securityAndNetwork/setKmsProviderState',
 60	        payload: kmsConfig,
 61	      }),
 62	    [dispatch]
 63	  );
 64	
 65	  React.useEffect(() => {
 66	    // only need to pass unique identifier for ceph-csi
 67	    const validUniqueId: boolean = isScEncryption
 68	      ? thalesState.uniqueId.valid && thalesState.uniqueId.value !== ''
 69	      : true;
 70	    const hasHandled: boolean =
 71	      validUniqueId && kmsConfigValidation(thalesState, ProviderNames.THALES);
 72	    if (thalesState.hasHandled !== hasHandled) {
 73	      updateThalesState({ ...thalesState, hasHandled });
 74	    }
 75	  }, [updateThalesState, thalesState, isScEncryption]);
 76	
 77	  const setUniqueID = (id: string) => {
 78	    thalesStateClone.uniqueId.value = id;
 79	    thalesStateClone.uniqueId.valid = id !== '';
 80	    updateThalesState(thalesStateClone);
 81	  };
 82	
 83	  const setTLSServer = (serverName: string) => {
 84	    thalesStateClone.tls = serverName;
 85	    updateThalesState(thalesStateClone);
 86	  };
 87	
 88	  const getValidatedUniqueIdProp = getValidatedProp(
 89	    !thalesState.uniqueId.valid
 90	  );
 91	
 92	  return (
 93	    <>
 94	      <NameAddrPort
 95	        className={className}
 96	        kmsState={thalesState}
 97	        kmsStateClone={thalesStateClone}
 98	        updateKmsState={updateThalesState}
 99	        canAcceptIP
100	      />
101	      {uploadInputItems(t).map((uploadItem: UploadInputItem) => (
102	        <FileUploadInput
103	          key={uploadItem.id}
104	          id={uploadItem.id}
105	          inputName={uploadItem.inputName}
106	          className={className}
107	          kmsState={thalesState}
108	          kmsStateClone={thalesStateClone}
109	          updateKmsState={updateThalesState}
110	        />
111	      ))}
112	      {isScEncryption && (
113	        <FormGroup
114	          fieldId="kms-unique-id"
115	          label={t('Unique identifier')}
116	          className={`${className}__form-body`}
117	          isRequired
118	        >
119	          <TextInput
120	            value={thalesState.uniqueId.value}
121	            onChange={(_event, id: string) => setUniqueID(id)}
122	            type="text"
123	            id="kms-unique-id"
124	            name="kms-unique-id"
125	            isRequired
126	            validated={getValidatedUniqueIdProp}
127	            data-test="kms-unique-id"
128	          />
129	          <FormHelperText>
130	            <HelperText>
131	              <HelperTextItem variant={getValidatedUniqueIdProp}>
132	                {getValidatedUniqueIdProp === ValidatedOptions.default
133	                  ? t(
134	                      'Unique ID of the key used for encrypting/decrypting. This only applies to encrpyted PVCs.'
135	                    )
136	                  : t('This is a required field')}
137	              </HelperTextItem>
138	            </HelperText>
139	          </FormHelperText>
140	        </FormGroup>
141	      )}
142	      <FormGroup
143	        fieldId="kms-tls-server"
144	        label={t('TLS server name')}
145	        className={`${className}__form-body`}
146	      >
147	        <TextInput
148	          value={thalesState.tls}
149	          onChange={(_event, serverName: string) => setTLSServer(serverName)}
150	          type="text"
151	          id="kms-tls-server"
152	          name="kms-tls-server"
153	          data-test="kms-tls-server"
154	        />
155	        <FormHelperText>
156	          <HelperText>
157	            <HelperTextItem>
158	              {t(
159	                'The endpoint server name. Useful when the KMIP endpoint does not have a DNS entry.'
160	              )}
161	            </HelperTextItem>
162	          </HelperText>
163	        </FormHelperText>
164	      </FormGroup>
165	    </>
166	  );
167	};
168	
169	type UploadInputItemType = (t: TFunction) => UploadInputItem[];

